INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (1, 1, 0, 0.0, "あたしだって\nやるときはやるよ！", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24001);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (1, 1, 1, 0.0, "ふぅ…\nこれであたしの仕事は\n終わりだね", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24002);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (1, 1, 2, 0.0, "終わった終わった\n一人でもなんとか\nなるもんだね", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24003);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (2, 2, 3, 0.0, "やったね！\nこれでようやく\nサボれるよ…", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24004);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (1, 1, 4, 0.0, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24005);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (2, 2, 5, 0.0, "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24006);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (2, 2, 6, 0.0, "あたしも意外と\nやるもんでしょ？", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24007);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (4, 4, 7, 0.0, "疲れた…\nねずみの逃げ足\n速すぎるよ…", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24008);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (4, 4, 8, 0.0, "このままじゃ\nまっひ～に\n叱られちゃうよ", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24009);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (4, 4, 9, 0.0, "まじめに\nやったんだけどな…\n悔しいな～", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24010);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (4, 4, 10, 0.0, "やられた…\nねずみって意外と\nてごわいね", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24011);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (4, 4, 11, 0.0, "おのれ～\nあたしのチーズを\n盗みやがって～！", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24012);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (1, 4, 12, 1.81, "疲れた…\nけど、次こそは\n守り抜くよ…", 10040, 0.0, 24, "2020/04/30 12:00:00", 102601, 0.0, "リン", "2030/12/17 14:59:59", 24013);
